async function handleCheckUpdate() {
  logger.info("Checking for Docker image update...");
  const { execFile } = await import("node:child_process");
  const { promisify } = await import("node:util");
  const execFileAsync = promisify(execFile);

  // Always check :stable — never use the running container's version tag,
  // which would always compare against itself and never detect a newer image.
  const checkTag = "stable";
  const pullImage = `ghcr.io/u2giants/popdam-bridge:${checkTag}`;

  try {
    await execFileAsync("docker", ["pull", pullImage, "--quiet"]);

    // Detect current container ID from hostname (Docker sets hostname = container ID
    // by default). This avoids hardcoding a container name that may differ between
    // Synology Container Manager stacks (e.g. "popdam-popdam-bridge-1" vs "popdam-bridge").
    const { stdout: hostnameOut } = await execFileAsync("hostname");
    const containerId = hostnameOut.trim();

    const { stdout: currentDigest } = await execFileAsync(
      "docker", ["inspect", containerId, "--format={{.Image}}"]

export async function handleRemoveAgentRegistration(body: Record<string, unknown>) {
  const agentId = requireString(body, "agent_id");
  const db = serviceClient();

  const { data: agent } = await db
    .from("agent_registrations")
    .select("id")
    .eq("id", agentId)
    .maybeSingle();

  if (!agent) return err("Agent registration not found", 404);

  const { error } = await db
    .from("agent_registrations")
    .delete()
    .eq("id", agentId);

  if (error) return err(error.message, 500);
  return json({ ok: true });
}

// ── trigger-scan ────────────────────────────────────────────────────

export async function handleTriggerScan(
  body: Record<string, unknown>,
  userId: string,
) {
  const targetAgentId = optionalString(body, "agent_id");
  const db = serviceClient();
  const requestId = crypto.randomUUID();

  // Auto-clear force_stop / scan_abort on all agents when user explicitly
  // triggers a scan — the user's intent is unambiguous.
  const { data: agents } = await db
    .from("agent_registrations")
    .select("id, metadata");

  let anyCleared = false;
  for (const a of agents || []) {
    const metadata = (a.metadata as Record<string, unknown>) || {};
    if (metadata.force_stop === true || metadata.scan_abort === true) {
      await db
        .from("agent_registrations")
        .update({
          metadata: { ...metadata, scan_abort: false, force_stop: false },
        })
        .eq("id", a.id);
      anyCleared = true;
    }
  }

  const { error } = await db.from("admin_config").upsert({
    key: "SCAN_REQUEST",
    value: {
      request_id: requestId,
      status: "pending",
      requested_at: new Date().toISOString(),
      requested_by: userId,
      target_agent_id: targetAgentId,
    },
    updated_at: new Date().toISOString(),
    updated_by: userId,
  });

  if (error) return err(error.message, 500);
  return json({ ok: true, request_id: requestId, force_stop_cleared: anyCleared });
}

// ── stop-scan ───────────────────────────────────────────────────────

export async function handleStopScan(_body: Record<string, unknown>) {
  const db = serviceClient();
  const now = new Date().toISOString();

  const { data: agents, error: agentsErr } = await db
    .from("agent_registrations")
    .select("id, metadata");
  if (agentsErr) return err(agentsErr.message, 500);

  for (const a of agents || []) {
    const metadata = (a.metadata as Record<string, unknown>) || {};
    const { error: updateErr } = await db
      .from("agent_registrations")
      .update({
        metadata: { ...metadata, scan_requested: false, scan_abort: true, force_stop: true },
      })
      .eq("id", a.id);
    if (updateErr) return err(updateErr.message, 500);
