  }

}

async function clearScanCheckpointWithRetry(context: string): Promise<boolean> {
  try {
    await api.clearCheckpoint();
    return true;
  } catch (e) {
    logger.warn(`Failed to clear checkpoint ${context} (retrying once)`, { error: (e as Error).message });
    return api.clearCheckpoint().then(() => true).catch((e2) => {
      logger.error(`Failed to clear checkpoint ${context} after retry`, {
        error: (e2 as Error).message,
      });
      return false;
    });
  }
}

async function processScanCandidates(candidates: FileCandidate[], sessionId: string) {
  // ── Change detection: ask cloud which files actually need processing ──
  const checkPayload = candidates.map((f) => ({
    relative_path: f.relativePath,
    modified_at: f.modifiedAt.toISOString(),
    file_size: f.fileSize,
  }));

  let changedSet: Set<string>;
  let needsThumbnailSet: Set<string>;
  try {
    // Server caps check-changed at 500 files per request.
    const CHECK_CHUNK_SIZE = 500;
    const allChanged: string[] = [];
    const allNeedsThumbnail: string[] = [];
    const existingIdentities: api.CheckChangedResult["existing_content_identities"] = [];
    for (let ci = 0; ci < checkPayload.length; ci += CHECK_CHUNK_SIZE) {
      const chunk = checkPayload.slice(ci, ci + CHECK_CHUNK_SIZE);
      const result = await api.checkChanged(chunk);
      allChanged.push(...result.changed);
      allNeedsThumbnail.push(...result.needs_thumbnail);
      existingIdentities.push(...result.existing_content_identities);
    }
    for (const identity of existingIdentities) {
      scanContentIdentitySeen.add(`${identity.quick_hash}\0${identity.filename}`);
    }
    changedSet = new Set(allChanged);
    needsThumbnailSet = new Set(allNeedsThumbnail);
  } catch (e) {
    // If check-changed fails, fall back to processing everything
    logger.warn("check-changed failed, processing entire scan", { error: (e as Error).message });
    changedSet = new Set(candidates.map((f) => f.relativePath));
    needsThumbnailSet = new Set();
  }

  const unchanged = candidates.length - changedSet.size - needsThumbnailSet.size;
  if (unchanged > 0) {
    // Note: files_checked was already incremented in the scanner when each file was yielded.
    // Do NOT add unchanged here — that would double-count those files in the counter.
    logger.debug(`Skipping ${unchanged}/${candidates.length} unchanged files in scan`);
  }

  // Files needing thumbnail retry: generate thumbnail + ingest (but they're otherwise unchanged)
  const thumbRetryFiles = candidates.filter((f) => needsThumbnailSet.has(f.relativePath));
  if (thumbRetryFiles.length > 0) {
    logger.info(`Retrying thumbnails for ${thumbRetryFiles.length} previously failed files`);
  }

  const filesToProcess = candidates.filter((f) => changedSet.has(f.relativePath));
  const allToProcess = [...filesToProcess, ...thumbRetryFiles];
  if (allToProcess.length === 0) {
    // Report progress even if nothing to process — fire-and-forget, never kill the scan
    api.scanProgress(sessionId, "running", counters, candidates[candidates.length - 1]?.relativePath, skippedDirs).catch(() => {});
    return;
  }

  // Process changed files with bounded thumbnail concurrency
  const concurrency = getEffectiveConcurrency();
  let i = 0;

  while (i < allToProcess.length) {
    const chunk = allToProcess.slice(i, i + concurrency);
    await Promise.all(chunk.map((file) => processFile(file)));
    i += concurrency;

    // Report progress — fire-and-forget, never kill the scan
    api.scanProgress(sessionId, "running", counters, allToProcess[Math.min(i, allToProcess.length) - 1]?.relativePath, skippedDirs).catch(() => {});
  }
}

async function processFile(file: FileCandidate) {
  // Skip files older than the configured scan min date
  if (cloudScanMinDate && file.modifiedAt < new Date(cloudScanMinDate)) {
    counters.skipped_before_min_date++;
    return;
  }

  // ── .ai pre-flight checks ───────────────────────────────────────────────────
  if (file.fileType === "ai") {
    // 1. Permanent ignore list (O(1) — loaded at scan start from scanner_ai_ignores table)
    if (aiIgnoreSet.has(file.relativePath)) {
      logger.debug("Skipping .ai: in permanent ignore list", { path: file.relativePath });
      counters.rejected_junk_file++;
      return;
    }

    // 2. PDF sibling check: if Foo.pdf exists in the same directory, skip Foo.ai.
    //    The PDF is the canonical distributable; the .ai is redundant source.
    const dir = dirname(file.absolutePath);
    const base = basename(file.filename, ".ai");
    const pdfSiblingPath = join(dir, `${base}.pdf`);
    try {
      await stat(pdfSiblingPath);
      // PDF sibling exists — record and skip forever
      logger.info("Skipping .ai: PDF sibling exists — recording in ignore list", { ai: file.relativePath, pdf: pdfSiblingPath });
      counters.rejected_junk_file++;
      aiIgnoreSet.add(file.relativePath);
      api.markAiIgnored(file.relativePath, "pdf_sibling").catch(() => {});
      return;
    } catch {
      // No sibling — continue
    }

    // 3. Sentinel check: reads 64KB of the file header to detect the Adobe
    //    "no PDF compatibility" marker. No mupdf needed — pure file read.
    //    Only runs on .ai files that passed the above two checks.
    const isSentinel = await isAiWithoutPdfCompat(file.absolutePath);
    if (isSentinel) {
      logger.info("Skipping .ai: no PDF compat (sentinel) — recording in ignore list", { path: file.relativePath });
      counters.rejected_junk_file++;
      aiIgnoreSet.add(file.relativePath);
      api.markAiIgnored(file.relativePath, "no_pdf_compat").catch(() => {});
      return;
    }
  }
  // ── end .ai pre-flight ──────────────────────────────────────────────────────

  try {
    // 1. Quick hash
    const { quick_hash, quick_hash_version } = await computeQuickHash(file.absolutePath);
    const contentIdentityKey = `${quick_hash}\0${file.filename}`;
    const skipMoveDetection = scanContentIdentitySeen.has(contentIdentityKey);
    scanContentIdentitySeen.add(contentIdentityKey);
    if (skipMoveDetection) {
      logger.info("Duplicate content identity seen in this scan; disabling hash move detection for this path", {
        file: file.relativePath,
        filename: file.filename,
      });
    }

    // 2. Thumbnail strategy — uses new policy if set, else legacy mode
    let thumb: { thumbnailUrl?: string; thumbnailError?: string; width?: number; height?: number; pdfPage2Url?: string } = {};
    const effectiveMode = windowsRenderPolicy?.mode ?? windowsRenderMode;
    const policy = windowsRenderPolicy;

    // ── Step 2a: Determine if we should defer to Windows BEFORE local thumbnailing ──
    const deferDecision = shouldDeferToWindows(
      file,
      quick_hash,
      effectiveMode,
      policy,
      windowsAgentHealthy,
      pendingRenderJobs,
    );

    // ── Step 2b: Either defer or attempt local thumbnail ──
    if (deferDecision.defer) {
      thumb = { thumbnailError: "deferred_to_windows_agent" };
    } else {
      const tempId = randomUUID();
      thumb = await processThumbnail(file, tempId);
    }

    // If the render produced a blank/white image (e.g. die-line templates), permanently ignore.
    // No point queuing for Windows — it would produce the same blank result.
    if (thumb.thumbnailError === "blank_render" && file.fileType === "ai") {
      logger.info("AI blank render — adding to permanent ignore list", { path: file.relativePath });
      aiIgnoreSet.add(file.relativePath);
      api.markAiIgnored(file.relativePath, "blank_render").catch(() => {});
    }

    // 3. Ingest to cloud
    const result = await api.ingest({
      relative_path: file.relativePath,
      filename: file.filename,
      file_type: file.fileType,
      file_size: file.fileSize,
      modified_at: file.modifiedAt.toISOString(),
      file_created_at: file.fileCreatedAt?.toISOString() || null,
      quick_hash,
      quick_hash_version,
      thumbnail_url: thumb.thumbnailUrl,
      thumbnail_error: thumb.thumbnailError,
      width: thumb.width,
      height: thumb.height,
      pdf_page2_url: thumb.pdfPage2Url,
      skip_move_detection: skipMoveDetection,
    });

    // Update counters based on API response
    switch (result.action) {
      case "created":
        counters.ingested_new++;
        break;
      case "moved":
        counters.moved_detected++;
        break;
      case "updated":
        counters.updated_existing++;
        break;
      case "noop":
        counters.noop_unchanged++;
        break;
      case "rejected_subfolder":
        counters.rejected_subfolder++;
        break;

Chunk ID: 395816
Wall time: 0.0000 seconds
Process exited with code 0
Original token count: 806
Output:
  // Heartbeat runs 4+ parallel DB queries server-side and can hit Supabase cold starts.
  // Use a 60s timeout (vs. 30s for other calls) so slow responses don't abort prematurely
  // and cause the force_scan command to never reach the agent.
  const data = await callApi("heartbeat", {
    agent_id: agentId,
    counters,
    last_error: lastError,
    version_info: versionInfo,
    diagnostics,
  }, 60_000);
  return data as unknown as HeartbeatResponse;
}

export interface IngestPayload {
  relative_path: string;
  filename: string;
  file_type: "psd" | "ai" | "pdf";
  file_size: number;
  modified_at: string;
  file_created_at: string | null;
  quick_hash: string;
  quick_hash_version: number;
  thumbnail_url?: string;
  thumbnail_error?: string;
  width?: number;
  height?: number;
  pdf_page2_url?: string;
  skip_move_detection?: boolean;
}

export interface IngestResult {
  action: "created" | "updated" | "moved" | "noop" | "rejected_subfolder" | "skipped";
  asset_id: string;
}

export async function ingest(payload: IngestPayload): Promise<IngestResult> {
  const data = await callApi("ingest", payload as unknown as Record<string, unknown>);
  return { action: data.action as IngestResult["action"], asset_id: data.asset_id as string };
}

export async function scanProgress(
  sessionId: string,
  status: "running" | "completed" | "completed_with_errors" | "failed",
  counters: Counters,
  currentPath?: string,
  skippedDirs?: string[],
): Promise<void> {
  await callApi("scan-progress", {
    session_id: sessionId,
    status,
    counters,
    current_path: currentPath,
    ...(skippedDirs && skippedDirs.length > 0 ? { skipped_dirs: skippedDirs } : {}),
  });
}


export async function queueRender(assetId: string, reason: string): Promise<string> {
  const data = await callApi("queue-render", { asset_id: assetId, reason });
  return data.job_id as string;
}

export async function reportPathTest(
  requestId: string,
  results: Record<string, unknown>,
): Promise<void> {
  await callApi("report-path-test", { request_id: requestId, results });
}

export interface DirEntry {
  name: string;
  is_dir: boolean;
  size?: number;
  modified?: string;
}

export async function reportDirBrowse(
  requestId: string,
  path: string,
  entries: DirEntry[],
): Promise<void> {
  await callApi("report-dir-browse", { request_id: requestId, path, entries });
}

export interface CheckChangedFile {
  relative_path: string;
  modified_at: string;
  file_size: number;
}

export interface CheckChangedResult {
  changed: string[];
  needs_thumbnail: string[];
  existing_content_identities: Array<{
    relative_path: string;
    filename: string;
    quick_hash: string;
  }>;
}

export async function checkChanged(files: CheckChangedFile[]): Promise<CheckChangedResult> {
  const data = await callApi("check-changed", { files });
  return {
    changed: (data.changed as string[]) || [],
    needs_thumbnail: (data.needs_thumbnail as string[]) || [],
    existing_content_identities: (data.existing_content_identities as CheckChangedResult["existing_content_identities"]) || [],
  };
}

export interface ScanCheckpoint {
  session_id: string;
  last_completed_dir: string;
  saved_at: string;

